css:
.loader {
  color: var(--loader-color, #14b8a6);
  --loader-secondary-color: #99f6e4;
  --loader-bg: #ffffff;
width: 9px;
height: 9px;
background: currentColor;
color: currentColor;
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px;
animation: l29 2s infinite;
}

@keyframes l29 {
10% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px #0000,0 9px,18px 9px #0000,
-18px 18px,0 18px,18px 18px;
}
20% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px #0000,
-18px 18px #0000,0 18px,18px 18px;
}
30% {
box-shadow:
-18px -9px,0 -9px #0000,18px -9px,
-18px 0 #0000, 18px 0 ,
-18px 9px,0 9px #0000,18px 9px,
-18px 18px #0000,0 18px,18px 18px #0000;
}
40% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 #0000, 18px 0 #0000,
-18px 9px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px;
}
50% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 #0000,
-18px 9px #0000,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px;
}
60% {
box-shadow:
-18px -9px,0 -9px #0000,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px #0000,0 9px,18px 9px,
-18px 18px #0000,0 18px,18px 18px;
}
70% {
box-shadow:
-18px -9px,0 -9px #0000,18px -9px #0000,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px,
-18px 18px #0000,0 18px,18px 18px;
}
80% {
box-shadow:
-18px -9px #0000,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px #0000;
}
90% {
box-shadow:
-18px -9px #0000,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px #0000,18px 9px,
-18px 18px,0 18px,18px 18px #0000;
}
}
